import React, { useEffect, useMemo, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  getWishlist,
  deleteFromWishlist,
} from "../redux/actions/wishListActon";
import { addToWishlist } from "../redux/actions/wishListActon";
import { addToCart, getCart } from "../redux/actions/cartAction";
import { getAllProducts } from "../features/products/productSlice";
import { AiFillHeart, AiOutlineHeart } from "react-icons/ai";
import { createSelector } from "reselect";
import Footer from "./Footer";
import { Navigation, Pagination, Autoplay } from "swiper/modules";
import SwiperCore from "swiper";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css/bundle";
import { Link, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

SwiperCore.use([Navigation, Pagination, Autoplay]);

const selectWishlist = createSelector(
  (state) => state?.auth?.wishlist?.wishlist,
  (wishlist) => wishlist || [],
);

function Wishlist() {
  const navigate = useNavigate();

  const getTokenFromLocalStorage = useMemo(() => {
    return localStorage.getItem("customer")
      ? JSON.parse(localStorage.getItem("customer"))
      : null;
  }, []);

  const config2 = useMemo(
    () => ({
      headers: {
        Authorization: `Bearer ${getTokenFromLocalStorage ? getTokenFromLocalStorage.token : ""}`,
        Accept: "application/json",
      },
    }),
    [getTokenFromLocalStorage],
  );
  const dispatch = useDispatch();

  const {
    product,
    isError: productError,
    message: productMessage,
  } = useSelector((state) => state.product);
  const addedToWish = useSelector(selectWishlist);
  const userState = useSelector((state) => state?.auth);
  const { items } = useSelector((state) => state.wishlist);

  const [showToast, setShowToast] = useState(false);
  const [toastMessage, setToastMessage] = useState("");
  const [productStates, setProductStates] = useState({});

  useEffect(() => {
    dispatch(getWishlist());
  }, [dispatch]);

  useEffect(() => {
    if (showToast) {
      const timer = setTimeout(() => {
        setShowToast(false);
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [showToast]);

  useEffect(() => {
    const initialStates = {};
    addedToWish?.forEach((item) => {
      initialStates[item._id] = true;
    });
    setProductStates(initialStates);
  }, [addedToWish]);

  const handleRemoveFromWishlist = (id) => {
    dispatch(deleteFromWishlist(id));
    toast.success("Removed from wishlist");
  };

  const handleAddToWishlist = (productId) => {
    dispatch(addToWishlist(productId, navigate, 1));
  };

  const handleToggle2 = async (productId) => {
    if (!userState.user) {
      setToastMessage("Sorry! You need to log in first.");
      setShowToast(true);
      return;
    }
    const isCurrentlyInWishlist = addedToWish.some(
      (item) => item._id === productId,
    );
    try {
      if (isCurrentlyInWishlist) {
        await dispatch(deleteFromWishlist(productId)).unwrap();
        setToastMessage("The item has been removed from your wishlist!");
      }
      setShowToast(true);
    } catch (error) {
      console.error("Error updating wishlist:", error);
    }
  };

  const newProducts = product
    .filter((product) => product.createdAt)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

  return (
    <>
      <style>{`
        @keyframes wlFadeIn {
          from { opacity: 0; transform: translateY(16px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .wl-item-card {
          animation: wlFadeIn 0.5s ease both;
        }
      `}</style>

      <main style={{ background: "#ffffff", minHeight: "100vh" }}>
        {/* Hero Header */}
        <section
          style={{
            background: "linear-gradient(135deg, #14b8a6 0%, #0d9488 100%)",
            padding: "80px 20px 50px",
            textAlign: "center",
            position: "relative",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              position: "absolute",
              top: "-60px",
              right: "-60px",
              width: "300px",
              height: "300px",
              background:
                "radial-gradient(circle, rgba(255,255,255,0.08) 0%, transparent 70%)",
              pointerEvents: "none",
            }}
          />
          <div style={{ position: "relative", zIndex: 2 }}>
            <span
              style={{
                display: "inline-block",
                fontSize: "10px",
                fontWeight: "800",
                letterSpacing: "0.3em",
                textTransform: "uppercase",
                color: "rgba(255,255,255,0.7)",
                marginBottom: "12px",
              }}
            >
              Your Collection
            </span>
            <h1
              style={{
                fontSize: "clamp(28px, 5vw, 42px)",
                fontWeight: "900",
                color: "#ffffff",
                margin: "0 0 8px",
                letterSpacing: "-1px",
              }}
            >
              Wishlist <span style={{ color: "#99f6e4" }}>♥</span>
            </h1>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: "8px",
                fontSize: "13px",
              }}
            >
              <Link
                to="/"
                style={{
                  color: "rgba(255,255,255,0.7)",
                  textDecoration: "none",
                }}
              >
                Home
              </Link>
              <span style={{ color: "rgba(255,255,255,0.4)" }}>›</span>
              <span style={{ color: "#ffffff", fontWeight: "600" }}>
                Wishlist
              </span>
            </div>
          </div>
        </section>

        {/* Wishlist Items */}
        <section
          style={{
            maxWidth: "1100px",
            margin: "0 auto",
            padding: "40px 20px 60px",
          }}
        >
          {items && items.length > 0 ? (
            <>
              {/* Count Badge */}
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "10px",
                  marginBottom: "24px",
                }}
              >
                <span
                  style={{
                    fontSize: "13px",
                    fontWeight: "700",
                    color: "#6b7280",
                  }}
                >
                  <strong style={{ color: "#111827" }}>{items.length}</strong>{" "}
                  items saved
                </span>
              </div>

              {/* Items Grid */}
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
                  gap: "20px",
                }}
              >
                {items.map((item, index) => (
                  <div
                    key={item._id}
                    className="wl-item-card"
                    style={{
                      background: "#ffffff",
                      border: "1px solid #f1f5f9",
                      borderRadius: "20px",
                      overflow: "hidden",
                      boxShadow: "0 2px 12px rgba(0,0,0,0.03)",
                      transition: "all 0.3s ease",
                      animationDelay: `${index * 0.08}s`,
                      position: "relative",
                    }}
                    onMouseOver={(e) => {
                      e.currentTarget.style.boxShadow =
                        "0 12px 40px rgba(0,0,0,0.08)";
                      e.currentTarget.style.borderColor =
                        "rgba(20,184,166,0.2)";
                      e.currentTarget.style.transform = "translateY(-4px)";
                    }}
                    onMouseOut={(e) => {
                      e.currentTarget.style.boxShadow =
                        "0 2px 12px rgba(0,0,0,0.03)";
                      e.currentTarget.style.borderColor = "#f1f5f9";
                      e.currentTarget.style.transform = "translateY(0)";
                    }}
                  >
                    {/* Remove Button */}
                    <button
                      onClick={() => handleRemoveFromWishlist(item?._id)}
                      style={{
                        position: "absolute",
                        top: "12px",
                        right: "12px",
                        zIndex: 3,
                        width: "32px",
                        height: "32px",
                        borderRadius: "50%",
                        background: "rgba(255,255,255,0.9)",
                        backdropFilter: "blur(4px)",
                        border: "1px solid #f1f5f9",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        cursor: "pointer",
                        color: "#ef4444",
                        transition: "all 0.2s",
                        fontSize: "14px",
                      }}
                      onMouseOver={(e) => {
                        e.currentTarget.style.background = "#fef2f2";
                        e.currentTarget.style.transform = "scale(1.1)";
                      }}
                      onMouseOut={(e) => {
                        e.currentTarget.style.background =
                          "rgba(255,255,255,0.9)";
                        e.currentTarget.style.transform = "scale(1)";
                      }}
                    >
                      ✕
                    </button>

                    {/* Image */}
                    <Link
                      to={`/productdetails/${item._id}`}
                      style={{ display: "block" }}
                    >
                      <div
                        style={{
                          height: "200px",
                          overflow: "hidden",
                          background: "#f8fafc",
                        }}
                      >
                        <img
                          src={
                            item?.colors?.[0]?.images?.[0]?.secure_url ||
                            "default-image-url"
                          }
                          alt={item?.title || "Product"}
                          style={{
                            width: "100%",
                            height: "100%",
                            objectFit: "cover",
                            transition: "transform 0.5s ease",
                          }}
                          onMouseOver={(e) =>
                            (e.target.style.transform = "scale(1.06)")
                          }
                          onMouseOut={(e) =>
                            (e.target.style.transform = "scale(1)")
                          }
                        />
                      </div>
                    </Link>

                    {/* Info */}
                    <div style={{ padding: "16px 18px 20px" }}>
                      <span
                        style={{
                          fontSize: "9px",
                          fontWeight: "800",
                          letterSpacing: "0.15em",
                          textTransform: "uppercase",
                          color: "#14b8a6",
                        }}
                      >
                        {item.category}
                      </span>
                      <h3
                        style={{
                          fontSize: "15px",
                          fontWeight: "700",
                          color: "#111827",
                          margin: "6px 0 8px",
                          lineHeight: 1.4,
                          overflow: "hidden",
                          textOverflow: "ellipsis",
                          whiteSpace: "nowrap",
                        }}
                      >
                        {item?.title || "No Title"}
                      </h3>
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "space-between",
                        }}
                      >
                        <span
                          style={{
                            fontSize: "18px",
                            fontWeight: "800",
                            color: "#111827",
                          }}
                        >
                          {item?.price}{" "}
                          <small
                            style={{
                              fontSize: "11px",
                              color: "#6b7280",
                              fontWeight: "600",
                            }}
                          >
                            ETB
                          </small>
                        </span>
                        <span
                          style={{
                            fontSize: "10px",
                            fontWeight: "700",
                            padding: "4px 10px",
                            borderRadius: "20px",
                            background:
                              item?.quantity > 0 ? "#ecfdf5" : "#fef2f2",
                            color: item?.quantity > 0 ? "#059669" : "#dc2626",
                            textTransform: "uppercase",
                            letterSpacing: "0.05em",
                          }}
                        >
                          {item?.quantity > 0 ? "In Stock" : "Out of Stock"}
                        </span>
                      </div>
                      <Link
                        to={`/productdetails/${item._id}`}
                        style={{
                          display: "block",
                          textAlign: "center",
                          marginTop: "14px",
                          padding: "11px",
                          background: "#14b8a6",
                          color: "#fff",
                          borderRadius: "12px",
                          fontSize: "11px",
                          fontWeight: "800",
                          letterSpacing: "0.1em",
                          textTransform: "uppercase",
                          textDecoration: "none",
                          transition: "all 0.2s",
                        }}
                        onMouseOver={(e) =>
                          (e.currentTarget.style.background = "#0d9488")
                        }
                        onMouseOut={(e) =>
                          (e.currentTarget.style.background = "#14b8a6")
                        }
                      >
                        View Details
                      </Link>
                    </div>
                  </div>
                ))}
              </div>

              {/* Bottom actions */}
              <div
                style={{
                  display: "flex",
                  gap: "16px",
                  justifyContent: "center",
                  marginTop: "40px",
                  flexWrap: "wrap",
                }}
              >
                <Link
                  to="/shop"
                  style={{
                    padding: "14px 32px",
                    background: "#14b8a6",
                    color: "#fff",
                    borderRadius: "14px",
                    fontSize: "12px",
                    fontWeight: "800",
                    letterSpacing: "0.1em",
                    textTransform: "uppercase",
                    textDecoration: "none",
                    boxShadow: "0 4px 16px rgba(20,184,166,0.25)",
                    transition: "all 0.2s",
                  }}
                  onMouseOver={(e) => {
                    e.currentTarget.style.background = "#0d9488";
                    e.currentTarget.style.transform = "translateY(-1px)";
                  }}
                  onMouseOut={(e) => {
                    e.currentTarget.style.background = "#14b8a6";
                    e.currentTarget.style.transform = "translateY(0)";
                  }}
                >
                  Continue Shopping
                </Link>
                <Link
                  to="/"
                  style={{
                    padding: "14px 32px",
                    background: "#f8fafc",
                    color: "#374151",
                    borderRadius: "14px",
                    fontSize: "12px",
                    fontWeight: "800",
                    letterSpacing: "0.1em",
                    textTransform: "uppercase",
                    textDecoration: "none",
                    border: "1px solid #e2e8f0",
                    transition: "all 0.2s",
                  }}
                  onMouseOver={(e) =>
                    (e.currentTarget.style.background = "#f1f5f9")
                  }
                  onMouseOut={(e) =>
                    (e.currentTarget.style.background = "#f8fafc")
                  }
                >
                  View All Products
                </Link>
              </div>
            </>
          ) : (
            /* Empty State */
            <div
              style={{
                textAlign: "center",
                padding: "80px 20px",
                background: "#f8fafc",
                borderRadius: "24px",
                border: "1px solid #f1f5f9",
              }}
            >
              <div style={{ fontSize: "56px", marginBottom: "16px" }}>💝</div>
              <h3
                style={{
                  fontSize: "22px",
                  fontWeight: "800",
                  color: "#111827",
                  margin: "0 0 8px",
                }}
              >
                Your wishlist is empty
              </h3>
              <p
                style={{
                  fontSize: "14px",
                  color: "#9ca3af",
                  margin: "0 0 28px",
                  maxWidth: "400px",
                  marginLeft: "auto",
                  marginRight: "auto",
                }}
              >
                Save items you love to your wishlist and come back to them
                later.
              </p>
              <Link
                to="/shop"
                style={{
                  display: "inline-block",
                  padding: "14px 36px",
                  background: "#14b8a6",
                  color: "#fff",
                  borderRadius: "14px",
                  fontSize: "12px",
                  fontWeight: "800",
                  letterSpacing: "0.1em",
                  textTransform: "uppercase",
                  textDecoration: "none",
                  boxShadow: "0 4px 16px rgba(20,184,166,0.25)",
                }}
              >
                Start Shopping
              </Link>
            </div>
          )}
        </section>

        {/* Suggested Products */}
        {newProducts.length > 0 && (
          <section
            style={{
              padding: "60px 20px 80px",
              borderTop: "1px solid #f1f5f9",
            }}
          >
            <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
              <div style={{ textAlign: "center", marginBottom: "36px" }}>
                <span
                  style={{
                    fontSize: "10px",
                    fontWeight: "800",
                    color: "#14b8a6",
                    letterSpacing: "0.3em",
                    textTransform: "uppercase",
                  }}
                >
                  You might also like
                </span>
                <h2
                  style={{
                    fontSize: "28px",
                    fontWeight: "800",
                    color: "#111827",
                    margin: "8px 0 0",
                    letterSpacing: "-0.5px",
                  }}
                >
                  New Arrivals
                </h2>
              </div>
              <Swiper
                spaceBetween={20}
                slidesPerView={2}
                autoplay={{ delay: 4000 }}
                breakpoints={{
                  640: { slidesPerView: 2 },
                  768: { slidesPerView: 3 },
                  1024: { slidesPerView: 4 },
                  1280: { slidesPerView: 5 },
                }}
              >
                {newProducts.map((product) => (
                  <SwiperSlide key={product._id}>
                    <div
                      style={{
                        background: "#ffffff",
                        border: "1px solid #f1f5f9",
                        borderRadius: "18px",
                        overflow: "hidden",
                        transition: "all 0.3s",
                      }}
                      onMouseOver={(e) => {
                        e.currentTarget.style.boxShadow =
                          "0 8px 24px rgba(0,0,0,0.06)";
                        e.currentTarget.style.borderColor =
                          "rgba(20,184,166,0.2)";
                      }}
                      onMouseOut={(e) => {
                        e.currentTarget.style.boxShadow = "none";
                        e.currentTarget.style.borderColor = "#f1f5f9";
                      }}
                    >
                      <Link
                        to={`/productdetails/${product._id}`}
                        style={{ display: "block" }}
                      >
                        <div
                          style={{
                            height: "180px",
                            overflow: "hidden",
                            background: "#f8fafc",
                          }}
                        >
                          <img
                            src={product?.colors?.[0]?.images?.[0]?.secure_url}
                            alt={product.title}
                            style={{
                              width: "100%",
                              height: "100%",
                              objectFit: "cover",
                              transition: "transform 0.5s",
                            }}
                            onMouseOver={(e) =>
                              (e.target.style.transform = "scale(1.06)")
                            }
                            onMouseOut={(e) =>
                              (e.target.style.transform = "scale(1)")
                            }
                          />
                        </div>
                      </Link>
                      <div
                        style={{
                          padding: "14px 16px 16px",
                          textAlign: "center",
                        }}
                      >
                        <h3
                          style={{
                            fontSize: "13px",
                            fontWeight: "700",
                            color: "#111827",
                            margin: "0 0 6px",
                            overflow: "hidden",
                            textOverflow: "ellipsis",
                            whiteSpace: "nowrap",
                          }}
                        >
                          {product.title}
                        </h3>
                        <div
                          style={{
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            gap: "8px",
                          }}
                        >
                          <span
                            style={{
                              fontSize: "15px",
                              fontWeight: "800",
                              color: "#111827",
                            }}
                          >
                            {product.price}{" "}
                            <small
                              style={{ fontSize: "10px", color: "#6b7280" }}
                            >
                              ETB
                            </small>
                          </span>
                          {product.oldPrice && (
                            <span
                              style={{
                                fontSize: "12px",
                                color: "#9ca3af",
                                textDecoration: "line-through",
                              }}
                            >
                              {product.oldPrice}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  </SwiperSlide>
                ))}
              </Swiper>
            </div>
          </section>
        )}
      </main>
    </>
  );
}

export default Wishlist;
